{
  "name": "Sophie Avatar",
  "description": "A premium AI avatar platform for creating cinematic, Saudi-dialect speaking avatars with luxury styling."
}

export interface SophiePlan {
  dialogue: string;
  emotionalTone: string;
  sceneLighting: string;
  wardrobeStyling: string;
  cameraAngle: string;
  veoPrompt: string;
}

export interface GeneratedMedia {
  videoUri?: string;
  audioBase64?: string;
}

export type AppStep = 'intro' | 'upload' | 'configure' | 'planning' | 'generating' | 'result';

import { GoogleGenAI, Type, Schema, Modality } from "@google/genai";
import { SophiePlan } from "../types";

// Helper to get the AI client.
// We prioritize the window.aistudio key if available (required for Veo), 
// otherwise fallback to env for text/audio if user hasn't selected a key yet.
const getAiClient = async () => {
  // Check for Veo-compatible key selection first
  if (window.aistudio && await window.aistudio.hasSelectedApiKey()) {
    // If selected, we must create a new instance to pick it up (it's injected internally)
    // We pass a dummy key because the internal injection overrides it, 
    // but the SDK requires a string in the constructor.
    return new GoogleGenAI({ apiKey: 'saved-key' });
  }
  // Fallback to env key
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

const SYSTEM_INSTRUCTION = `
You are the AI brain of "Sophie Avatar", a premium luxury AI platform.
Your goal is to transform user inputs into a cohesive, cinematic plan for an AI avatar video.

Brand Identity:
- Modern, Luxury, Minimal.
- Black and gold aesthetic.
- Female empowerment.
- GCC/Saudi audience focused.

The Avatar (Sophie):
- Speaks modern Saudi dialect (female tone).
- Confident, elegant, playful.
- Not robotic.
- Uses natural Saudi expressions.

Task:
Analyze the character image, clothing items, location, and dialogue request.
Generate a structured JSON plan containing the final dialect dialogue, scene details, and a prompt suitable for a video generation model (Veo).
`;

export const generateSophiePlan = async (
  characterBase64: string,
  clothesBase64s: string[],
  location: string,
  dialogueRequest: string
): Promise<SophiePlan> => {
  const ai = await getAiClient();

  const parts: any[] = [];

  // Add Character
  if (characterBase64) {
    parts.push({ inlineData: { mimeType: 'image/jpeg', data: characterBase64 } });
    parts.push({ text: "This is the character reference image." });
  }

  // Add Clothes
  clothesBase64s.forEach((cloth, idx) => {
    parts.push({ inlineData: { mimeType: 'image/jpeg', data: cloth } });
    parts.push({ text: `Clothing item ${idx + 1} reference.` });
  });

  // Add Request
  const prompt = `
    Location: ${location}
    Dialogue Request: "${dialogueRequest}"

    Based on the images and text provided, generate a Sophie Avatar Plan.
    The 'veoPrompt' should be a highly detailed English prompt for a video generation model. 
    It must describe the character (based on the reference) wearing the provided clothing items, in the specified location, with the specified lighting and mood. 
    The character should be moving slightly, looking elegant. 
    Do NOT include dialogue in the veoPrompt, only visual descriptions.
  `;
  parts.push({ text: prompt });

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      dialogue: { type: Type.STRING, description: "The final dialogue in Saudi Arabic dialect." },
      emotionalTone: { type: Type.STRING, description: "Description of the emotional tone." },
      sceneLighting: { type: Type.STRING, description: "Description of the scene lighting." },
      wardrobeStyling: { type: Type.STRING, description: "A refined description of the combined wardrobe." },
      cameraAngle: { type: Type.STRING, description: "Suggested cinematic camera angle." },
      veoPrompt: { type: Type.STRING, description: "A detailed visual prompt for the video generation model." },
    },
    required: ["dialogue", "emotionalTone", "sceneLighting", "wardrobeStyling", "cameraAngle", "veoPrompt"],
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview', // Using Pro for complex reasoning and multimodal understanding
    contents: { parts },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: schema,
      thinkingConfig: { thinkingBudget: 1024 } // Allow some thinking for the creative styling
    }
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate plan");
  return JSON.parse(text) as SophiePlan;
};

export const generateSophieAudio = async (text: string): Promise<string> => {
  const ai = await getAiClient();

  // We want a female Arabic voice. 
  // 'Zephyr' is a good general placeholder in the SDK examples, but for Arabic TTS via Gemini,
  // we rely on the model to detect language. We can hint with system instructions or just the text.
  // Currently, the TTS endpoint supports specific voices. 'Kore' is female-sounding.

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, // Selecting a female voice
        },
      },
    },
  });

  const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!audioData) throw new Error("Failed to generate audio");
  return audioData;
};

export const generateSophieVideo = async (
  characterBase64: string,
  prompt: string
): Promise<string> => {
  const ai = await getAiClient();

  // Veo requires user selected key.
  // We assume the check has been done in the UI before calling this.

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: characterBase64,
      mimeType: 'image/jpeg',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16' // Portrait for social media
    }
  });

  // Poll for completion
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) throw new Error("Failed to generate video");

  return videoUri;
};

// Helper for Key Selection
declare global {
  interface Window {
    aistudio?: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export const ensureApiKeySelected = async (): Promise<boolean> => {
  if (!window.aistudio) return false;
  const hasKey = await window.aistudio.hasSelectedApiKey();
  if (hasKey) return true;

  try {
    await window.aistudio.openSelectKey();
    return true; // Assume success if no error thrown
  } catch (e) {
    console.error("Key selection failed or cancelled", e);
    return false;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-8 py-3 font-cinzel font-semibold transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed uppercase tracking-wider";

  const variants = {
    primary: "bg-gradient-to-r from-amber-600 to-amber-400 text-black hover:from-amber-500 hover:to-amber-300 shadow-[0_0_15px_rgba(217,119,6,0.3)]",
    secondary: "bg-neutral-800 text-amber-500 border border-neutral-700 hover:bg-neutral-700 hover:border-amber-500/50",
    outline: "bg-transparent border border-amber-500 text-amber-500 hover:bg-amber-500/10"
  };

  const width = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${width} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

