import React, { useRef } from 'react';

interface FileUploadProps {
  label: string;
  onFileSelect: (base64: string) => void;
  accept?: string;
  preview?: string | null;
}

export const FileUpload: React.FC<FileUploadProps> = ({ label, onFileSelect, accept = "image/*", preview }) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onFileSelect(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="w-full group">
      <label className="block text-amber-500 text-sm font-bold mb-2 uppercase tracking-wide">
        {label}
      </label>
      <div 
        onClick={() => inputRef.current?.click()}
        className={`
          relative w-full h-48 border-2 border-dashed border-neutral-700 
          hover:border-amber-500/50 transition-colors cursor-pointer 
          flex flex-col items-center justify-center bg-neutral-900/50 overflow-hidden
          ${preview ? 'border-amber-500/30' : ''}
        `}
      >
        <input 
          ref={inputRef}
          type="file" 
          accept={accept} 
          className="hidden" 
          onChange={handleFileChange}
        />

        {preview ? (
          <img src={preview} alt="Preview" className="w-full h-full object-cover opacity-80 group-hover:opacity-100 transition-opacity" />
        ) : (
          <div className="text-center p-4">
            <svg className="w-10 h-10 mx-auto text-neutral-500 mb-2 group-hover:text-amber-500 transition-colors" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path>
            </svg>
            <p className="text-neutral-400 text-sm">Click to upload image</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './components/Button';
import { GlassCard } from './components/GlassCard';
import { FileUpload } from './components/FileUpload';
import { generateSophiePlan, generateSophieAudio, generateSophieVideo, ensureApiKeySelected } from './services/geminiService';
import { SophiePlan, AppStep } from './types';

// Extract base64 content from data URL
const extractBase64 = (dataUrl: string) => dataUrl.split(',')[1];

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('intro');
  const [characterImg, setCharacterImg] = useState<string | null>(null);
  const [clothesImg, setClothesImg] = useState<string | null>(null); // Simplified to single item for demo
  const [location, setLocation] = useState('Luxury Riyadh Villa at Sunset');
  const [dialogue, setDialogue] = useState('Welcome to my world.');

  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<SophiePlan | null>(null);
  const [media, setMedia] = useState<{ videoUri?: string; audioBase64?: string }>({});
  const [error, setError] = useState<string | null>(null);

  // --- Handlers ---

  const handleGeneratePlan = async () => {
    if (!characterImg) {
      setError("Please upload a character image.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // 1. Generate The Plan (Text/JSON)
      const planResult = await generateSophiePlan(
        extractBase64(characterImg),
        clothesImg ? [extractBase64(clothesImg)] : [],
        location,
        dialogue
      );
      setPlan(planResult);
      setStep('planning');
    } catch (err: any) {
      setError(err.message || "Failed to generate plan.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateMedia = async () => {
    if (!plan || !characterImg) return;

    setIsLoading(true);
    setError(null);
    setStep('generating');

    try {
      // 2. Ensure Key for Veo
      const hasKey = await ensureApiKeySelected();
      if (!hasKey) {
        throw new Error("API Key selection is required for video generation.");
      }

      // 3. Generate Video & Audio in parallel
      const [videoUri, audioData] = await Promise.all([
        generateSophieVideo(extractBase64(characterImg), plan.veoPrompt),
        generateSophieAudio(plan.dialogue)
      ]);

      // Note: Video URI requires key appendage to fetch if it's a direct link, 
      // but usually the browser handles the download link redirection. 
      // For Veo in standard usage, we might need to proxy or just append key if strictly required by docs.
      // Based on docs: "You must append an API key when fetching from the download link."
      // We will append it in the VideoPlayer component or here.
      // Since we don't have the user's selected key in clear text easily in all envs (only injected),
      // we rely on the `uri` being accessible or the user's browser session.
      // However, the docs say: fetch(`${downloadLink}&key=${process.env.API_KEY}`). 
      // The injected key isn't exposed as process.env.API_KEY in the browser for client side fetch directly unless we have it.
      // For this demo, we will construct the URL assuming the key is needed. 
      // But since we can't extract the injected key, we will display the URI and hope the authenticated session handles it 
      // or we ask the user to provide it in a real app.
      // *Workaround for Demo*: We will assume the `videoUri` is playable or we pass it to a video tag. 
      // If it fails due to auth, we'll note it. 
      // (Actually, the docs imply we need the key string. In a strict "injected key" environment, this is tricky.
      // We will use process.env.API_KEY if available as a fallback for the fetch url).

      const finalVideoUrl = process.env.API_KEY ? `${videoUri}&key=${process.env.API_KEY}` : videoUri;

      setMedia({ videoUri: finalVideoUrl, audioBase64: audioData });
      setStep('result');

    } catch (err: any) {
      console.error(err);
      setError("Generation failed. " + (err.message || ""));
      setStep('planning'); // Go back
    } finally {
      setIsLoading(false);
    }
  };

  // --- Renders ---

  const renderIntro = () => (
    <div className="flex flex-col items-center text-center space-y-8 animate-fade-in max-w-2xl mx-auto">
      <h1 className="text-6xl md:text-8xl luxury-gradient font-cinzel tracking-widest mb-4">SOPHIE</h1>
      <p className="text-xl text-neutral-400 font-light tracking-wide max-w-lg">
        THE PREMIER AI AVATAR PLATFORM FOR THE GCC. <br />
        <span className="text-amber-500">ELEGANCE. INTELLIGENCE. LUXURY.</span>
      </p>
      <Button onClick={() => setStep('upload')} className="mt-8 text-lg px-12 py-4">
        Begin Experience
      </Button>
    </div>
  );

  const renderUpload = () => (
    <div className="w-full max-w-4xl mx-auto grid md:grid-cols-2 gap-8">
      <GlassCard className="space-y-6">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">The Muse</h2>
        <FileUpload 
          label="Character Base" 
          onFileSelect={setCharacterImg} 
          preview={characterImg}
        />
      </GlassCard>

      <GlassCard className="space-y-6">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">The Wardrobe</h2>
        <FileUpload 
          label="Outfit / Abaya" 
          onFileSelect={setClothesImg} 
          preview={clothesImg}
        />
        <p className="text-xs text-neutral-500 mt-2">*Upload an image of the desired clothing style.</p>

        <div className="pt-8 flex justify-end">
           <Button 
            disabled={!characterImg}
            onClick={() => setStep('configure')}
           >
             Next: Styling
           </Button>
        </div>
      </GlassCard>
    </div>
  );

  const renderConfigure = () => (
    <GlassCard className="max-w-3xl mx-auto w-full space-y-8">
      <div className="flex items-center justify-between border-b border-neutral-800 pb-4">
        <h2 className="text-3xl text-amber-500 font-cinzel">Direct The Scene</h2>
        <span className="text-neutral-500 text-sm tracking-widest">STEP 02/03</span>
      </div>

      <div className="space-y-6">
        <div>
          <label className="block text-amber-500 text-sm font-bold mb-2 uppercase">Location & Atmosphere</label>
          <input 
            type="text" 
            value={location}
            onChange={(e) => setLocation(e.target.value)}
            className="w-full bg-neutral-950 border border-neutral-700 p-4 text-white focus:border-amber-500 focus:outline-none transition-colors"
            placeholder="e.g. Luxury Riyadh villa at sunset..."
          />
        </div>

        <div>
          <label className="block text-amber-500 text-sm font-bold mb-2 uppercase">Dialogue Request</label>
          <textarea 
            rows={3}
            value={dialogue}
            onChange={(e) => setDialogue(e.target.value)}
            className="w-full bg-neutral-950 border border-neutral-700 p-4 text-white focus:border-amber-500 focus:outline-none transition-colors"
            placeholder="What should Sophie say?"
          />
        </div>
      </div>

      <div className="flex justify-between items-center pt-4">
        <button onClick={() => setStep('upload')} className="text-neutral-500 hover:text-white transition-colors uppercase text-sm">Back</button>
        <Button onClick={handleGeneratePlan} disabled={isLoading}>
          {isLoading ? 'Analyzing...' : 'Generate Creative Plan'}
        </Button>
      </div>
    </GlassCard>
  );

  const renderPlanning = () => (
    <div className="max-w-5xl mx-auto w-full grid lg:grid-cols-2 gap-8">
      {/* Left: The Plan Details */}
      <GlassCard className="space-y-6 h-full">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">Creative Direction</h2>

        {plan && (
          <div className="space-y-6 text-sm md:text-base">
            <div>
              <h3 className="text-neutral-500 uppercase text-xs mb-1">Target Dialogue (Saudi Dialect)</h3>
              <p className="text-xl arabic-text text-white leading-relaxed" dir="rtl">{plan.dialogue}</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <h3 className="text-neutral-500 uppercase text-xs mb-1">Tone</h3>
                <p className="text-amber-100">{plan.emotionalTone}</p>
              </div>
              <div>
                <h3 className="text-neutral-500 uppercase text-xs mb-1">Lighting</h3>
                <p className="text-amber-100">{plan.sceneLighting}</p>
              </div>
            </div>

            <div>
              <h3 className="text-neutral-500 uppercase text-xs mb-1">Wardrobe Styling</h3>
              <p className="text-neutral-300 italic">"{plan.wardrobeStyling}"</p>
            </div>

            <div>
              <h3 className="text-neutral-500 uppercase text-xs mb-1">Camera</h3>
              <p className="text-neutral-300">{plan.cameraAngle}</p>
            </div>
          </div>
        )}
      </GlassCard>

      {/* Right: Confirmation */}
      <div className="flex flex-col space-y-8">
        <GlassCard className="flex-1 flex flex-col justify-center items-center text-center space-y-4 border-amber-500/20">
          <h3 className="text-xl font-cinzel text-white">Ready to Produce?</h3>
          <p className="text-neutral-400 text-sm max-w-xs">
            This will generate a high-definition video using Veo and synthesize the voice.
            <br/><br/>
            <span className="text-amber-600 text-xs">REQUIRES PAID API KEY SELECTION</span>
          </p>
          <Button onClick={handleGenerateMedia} className="w-full max-w-xs py-4 shadow-[0_0_30px_rgba(217,119,6,0.15)]">
            Generate Cinematic Media
          </Button>
          <button onClick={() => setStep('configure')} className="text-xs text-neutral-600 hover:text-neutral-400 mt-4 uppercase">Adjust Parameters</button>
        </GlassCard>
      </div>
    </div>
  );

  const renderGenerating = () => (
    <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-8 text-center">
      <div className="relative w-24 h-24">
        <div className="absolute inset-0 border-4 border-neutral-800 rounded-full"></div>
        <div className="absolute inset-0 border-t-4 border-amber-500 rounded-full animate-spin"></div>
      </div>
      <div>
        <h2 className="text-3xl font-cinzel text-white mb-2">Producing Content</h2>
        <p className="text-amber-500/80 animate-pulse">Synthesizing audio and rendering video frames...</p>
        <p className="text-neutral-600 text-sm mt-4">This may take up to 2 minutes.</p>
      </div>
    </div>
  );

  const renderResult = () => (
    <div className="max-w-6xl mx-auto w-full grid lg:grid-cols-3 gap-8">
      {/* Video Result */}
      <GlassCard className="lg:col-span-2 p-0 overflow-hidden relative bg-black aspect-[9/16] lg:aspect-video flex items-center justify-center">
        {media.videoUri ? (
          <video 
            src={media.videoUri} 
            controls 
            autoPlay 
            loop 
            className="w-full h-full object-contain"
            crossOrigin="anonymous"
          />
        ) : (
          <p className="text-red-500">Video generation unavailable.</p>
        )}
      </GlassCard>

      {/* Audio & Details */}
      <div className="flex flex-col space-y-6">
         <GlassCard>
          <h3 className="text-amber-500 font-cinzel mb-4">Voice Synthesis</h3>
          {media.audioBase64 ? (
            <audio controls className="w-full" src={`data:audio/mp3;base64,${media.audioBase64}`} />
          ) : (
            <p className="text-neutral-500 text-sm">Audio unavailable</p>
          )}
         </GlassCard>

         <GlassCard className="flex-1">
           <h3 className="text-amber-500 font-cinzel mb-4">Production Notes</h3>
           <div className="space-y-4 text-sm text-neutral-300">
             <p><span className="text-neutral-500 block text-xs uppercase">Dialogue</span> {plan?.dialogue}</p>
             <p><span className="text-neutral-500 block text-xs uppercase">Styling</span> {plan?.wardrobeStyling}</p>
           </div>

           <div className="mt-8 pt-8 border-t border-neutral-800">
             <Button variant="outline" fullWidth onClick={() => setStep('intro')}>Create New Avatar</Button>
           </div>
         </GlassCard>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-neutral-200 selection:bg-amber-500/30 selection:text-amber-200 flex flex-col">
      {/* Header */}
      <header className="py-6 px-8 border-b border-neutral-900 flex justify-between items-center sticky top-0 bg-black/80 backdrop-blur-lg z-50">
        <div className="text-2xl font-cinzel font-bold text-white tracking-widest cursor-pointer" onClick={() => setStep('intro')}>
          SOPHIE <span className="text-amber-600">.</span>
        </div>
        <div className="text-xs font-bold text-neutral-500 tracking-[0.2em] hidden md:block">
          AI AVATAR LUXURY SUITE
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col p-4 md:p-8 lg:p-12 relative overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-amber-600/10 rounded-full blur-[128px] pointer-events-none"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-amber-900/10 rounded-full blur-[128px] pointer-events-none"></div>

        <div className="relative z-10 w-full max-w-7xl mx-auto flex-1 flex flex-col justify-center">
          {error && (
            <div className="mb-6 p-4 border border-red-900/50 bg-red-900/10 text-red-200 text-center rounded">
              {error}
            </div>
          )}

          {step === 'intro' && renderIntro()}
          {step === 'upload' && renderUpload()}
          {step === 'configure' && renderConfigure()}
          {step === 'planning' && renderPlanning()}
          {step === 'generating' && renderGenerating()}
          {step === 'result' && renderResult()}
        </div>
      </main>

      {/* Footer */}
      <footer className="py-6 text-center text-neutral-700 text-xs tracking-widest uppercase">
        Powered by Gemini 2.5 & Veo • Sophie Avatar Platform © 2025
      </footer>
    </div>
  );
};

