// Extract base64 content from data URL
const extractBase64 = (dataUrl: string) => dataUrl.split(',')[1];

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('intro');
  const [characterImg, setCharacterImg] = useState<string | null>(null);
  const [clothesImg, setClothesImg] = useState<string | null>(null); // Simplified to single item for demo
  const [location, setLocation] = useState('Luxury Riyadh Villa at Sunset');
  const [dialogue, setDialogue] = useState('Welcome to my world.');

  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<SophiePlan | null>(null);
  const [media, setMedia] = useState<{ videoUri?: string; audioBase64?: string }>({});
  const [error, setError] = useState<string | null>(null);

  // --- Handlers ---

  const handleGeneratePlan = async () => {
    if (!characterImg) {
      setError("Please upload a character image.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // 1. Generate The Plan (Text/JSON)
      const planResult = await generateSophiePlan(
        extractBase64(characterImg),
        clothesImg ? [extractBase64(clothesImg)] : [],
        location,
        dialogue
      );
      setPlan(planResult);
      setStep('planning');
    } catch (err: any) {
      setError(err.message || "Failed to generate plan.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateMedia = async () => {
    if (!plan || !characterImg) return;

    setIsLoading(true);
    setError(null);
    setStep('generating');

    try {
      // 2. Ensure Key for Veo
      const hasKey = await ensureApiKeySelected();
      if (!hasKey) {
        throw new Error("API Key selection is required for video generation.");
      }

      // 3. Generate Video & Audio in parallel
      const [videoUri, audioData] = await Promise.all([
        generateSophieVideo(extractBase64(characterImg), plan.veoPrompt),
        generateSophieAudio(plan.dialogue)
      ]);

      // 4. Robust video handling: Fetch blob to bypass potential auth/CORS issues with direct links
      let finalVideoUrl = videoUri;
      try {
        const apiKey = process.env.API_KEY;
        const fetchUrl = apiKey && !videoUri.includes('key=') 
          ? `${videoUri}&key=${apiKey}` 
          : videoUri;

        console.log("Fetching video...");
        const response = await fetch(fetchUrl);
        if (response.ok) {
          const blob = await response.blob();
          finalVideoUrl = URL.createObjectURL(blob);
        } else {
          console.warn("Video fetch failed, using direct link fallback.");
          // Fallback to direct link with key appended
          if (apiKey && !videoUri.includes('key=')) {
            finalVideoUrl = `${videoUri}&key=${apiKey}`;
          }
        }
      } catch (e) {
        console.warn("Video fetch error:", e);
        // Fallback to direct link with key appended
        if (process.env.API_KEY && !videoUri.includes('key=')) {
           finalVideoUrl = `${videoUri}&key=${process.env.API_KEY}`;
        }
      }

      setMedia({ videoUri: finalVideoUrl, audioBase64: audioData });
      setStep('result');

