  const renderUpload = () => (
    <div className="w-full max-w-4xl mx-auto grid md:grid-cols-2 gap-8">
      <GlassCard className="space-y-6">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">The Muse</h2>
