      veoPrompt: { type: Type.STRING, description: "A detailed visual prompt for the video generation model focused on speaking and lip movement." },
    },
    required: ["dialogue", "emotionalTone", "sceneLighting", "wardrobeStyling", "cameraAngle", "veoPrompt"],
  };

  const specificInstruction = language === 'saudi' ? SAUDI_INSTRUCTION : ENGLISH_INSTRUCTION;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview', 
    contents: { parts },
    config: {
      systemInstruction: BASE_SYSTEM_INSTRUCTION + "\n" + specificInstruction,
      responseMimeType: "application/json",
      responseSchema: schema,
      thinkingConfig: { thinkingBudget: 1024 }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate plan");
  return JSON.parse(text) as SophiePlan;
};

export const generateSophieAudio = async (text: string): Promise<string> => {
  const ai = await getAiClient();

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, 
        },
      },
    },
  });

  const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!audioData) throw new Error("Failed to generate audio");
  return audioData;
};

export const generateSophieVideo = async (
  characterBase64: string,
  prompt: string
): Promise<string> => {
  const ai = await getAiClient();

  // Using fast-generate-preview for speed. 
  // The prompt is engineered to force "speaking" behavior to simulate lip sync.
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt, 
    image: {
      imageBytes: characterBase64,
      mimeType: 'image/jpeg',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  // Polling loop
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) throw new Error("Video generation failed to return a URI.");

  return videoUri;
};

export const ensureApiKeySelected = async (): Promise<boolean> => {
    const win = window as any;
    if (win.aistudio) {
        if (await win.aistudio.hasSelectedApiKey()) {
            return true;
        }
        try {
            const success = await win.aistudio.openSelectKey();
            return success;
        } catch (e) {
            console.error(e);
            return false;
        }
    }
    // Fallback for dev environments if needed
    return !!process.env.API_KEY; 
};

