    }
  };

  const handleGenerateMedia = async () => {
    if (!plan || !characterImg) return;

    setIsLoading(true);
    setError(null);
    setStep('generating');

    try {
      // 2. Ensure Key for Veo
      const hasKey = await ensureApiKeySelected();
      if (!hasKey) {
        throw new Error("API Key selection is required for video generation.");
      }

      // 3. Generate Video & Audio in parallel
      const [videoUri, audioData] = await Promise.all([
        generateSophieVideo(extractBase64(characterImg), plan.veoPrompt),
        generateSophieAudio(plan.dialogue)
      ]);

      // 4. Robust video handling: Fetch blob to bypass potential auth/CORS issues with direct links
      let finalVideoUrl = videoUri;
      try {
        const apiKey = process.env.API_KEY;
        const fetchUrl = apiKey && !videoUri.includes('key=') 
          ? `${videoUri}&key=${apiKey}` 
          : videoUri;

        console.log("Fetching video...");
        const response = await fetch(fetchUrl);
        if (response.ok) {
          const blob = await response.blob();
          finalVideoUrl = URL.createObjectURL(blob);
        } else {
          console.warn("Video fetch failed, using direct link fallback.");
