import { GoogleGenAI, Type, Schema, Modality } from "@google/genai";
import { SophiePlan, Language, VideoResolution } from "../types";

// Helper to get the AI client.
const getAiClient = async () => {
  const win = window as any;
  if (win.aistudio && await win.aistudio.hasSelectedApiKey()) {
    return new GoogleGenAI({ apiKey: 'saved-key' });
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

// Helper to parse Data URL to get mimeType and base64 data
const parseDataUrl = (dataUrl: string) => {
  const parts = dataUrl.split(',');
  if (parts.length !== 2) {
    throw new Error("Invalid image data format.");
  }
  const mimeMatch = parts[0].match(/:(.*?);/);
  if (!mimeMatch) {
    throw new Error("Could not detect image MIME type.");
  }
  return {
    mimeType: mimeMatch[1],
    data: parts[1]
  };
};

const SAUDI_INSTRUCTION = `
CRITICAL LANGUAGE RULE (SAUDI):
- The 'dialogue' output must be in **STRICT AUTHENTIC SAUDI ARABIC DIALECT** (Najdi or Hejazi).
- **ABSOLUTELY FORBIDDEN:** Modern Standard Arabic (Fusha). Do not use formal phrasing.
- **ABSOLUTELY FORBIDDEN:** English words in the dialogue.
- Use deep local slang, fillers (e.g., "يعني", "ترا", "يا هلا", "أبشر", "سم", "وش دعوة"), and cultural nuances.
`;

const ENGLISH_INSTRUCTION = `
CRITICAL LANGUAGE RULE (ENGLISH):
- The 'dialogue' output must be in **ELEGANT LUXURY ENGLISH**.
- The tone should be sophisticated, international, and welcoming.
- You may include very slight, subtle Arabic loanwords only if they fit a luxury context (e.g., "Habibi", "Yalla") but keep it 99% English.
`;

const BASE_SYSTEM_INSTRUCTION = `
You are the AI brain of "Sophie Avatar", a premium luxury AI platform.

Brand Identity:
- Modern, Luxury, Minimal.
- Black and gold aesthetic.
- Female empowerment.

Task:
Analyze the character image, clothing items, location, and dialogue request.
Generate a structured JSON plan containing the final dialogue, scene details, and a prompt suitable for a video generation model (Veo).
`;

export const generateSophiePlan = async (
  characterDataUrl: string,
  clothesDataUrls: string[],
  location: string,
  dialogueRequest: string,
  language: Language
): Promise<SophiePlan> => {
  const ai = await getAiClient();

  const parts: any[] = [];

  // Add Character
  if (characterDataUrl) {
    const { mimeType, data } = parseDataUrl(characterDataUrl);
    parts.push({ inlineData: { mimeType, data } });
    parts.push({ text: "This is the character reference image." });
  }

  // Add Clothes
  clothesDataUrls.forEach((clothUrl, idx) => {
    const { mimeType, data } = parseDataUrl(clothUrl);
    parts.push({ inlineData: { mimeType, data } });
    parts.push({ text: `Clothing item ${idx + 1} reference.` });
  });

  // Add Request
  const prompt = `
    Location: ${location}
    Dialogue Request: "${dialogueRequest}"
    Target Language: ${language === 'saudi' ? 'Saudi Arabic Dialect' : 'English'}

    Based on the images and text provided, generate a Sophie Avatar Plan.

    CRITICAL VEO PROMPT INSTRUCTION:
    The 'veoPrompt' is for a video generation model to simulate a speaking avatar.
    It MUST start with: "Cinematic close-up portrait of..."
    You MUST explicitly include these keywords to simulate lip-sync: "The subject is looking directly into the camera lens. Her lips are moving and articulating words. She is speaking continuously. Expressive facial animation."
    Describe the clothing, the luxury location, and the lighting.
    The character must appear alive, engaged, and actively talking to the viewer.
  `;
  parts.push({ text: prompt });

  const schema: Schema = {
    type: Type.OBJECT,
    properties: {
      dialogue: { type: Type.STRING, description: "The final dialogue in the requested language." },
      emotionalTone: { type: Type.STRING, description: "Description of the emotional tone." },
      sceneLighting: { type: Type.STRING, description: "Description of the scene lighting." },
      wardrobeStyling: { type: Type.STRING, description: "A refined description of the combined wardrobe." },
      cameraAngle: { type: Type.STRING, description: "Suggested cinematic camera angle." },
      veoPrompt: { type: Type.STRING, description: "A detailed visual prompt for the video generation model focused on speaking and lip movement." },
    },
    required: ["dialogue", "emotionalTone", "sceneLighting", "wardrobeStyling", "cameraAngle", "veoPrompt"],
  };

  const specificInstruction = language === 'saudi' ? SAUDI_INSTRUCTION : ENGLISH_INSTRUCTION;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview', 
    contents: { parts },
    config: {
      systemInstruction: BASE_SYSTEM_INSTRUCTION + "\n" + specificInstruction,
      responseMimeType: "application/json",
      responseSchema: schema,
      thinkingConfig: { thinkingBudget: 1024 }
    }
  });

  const text = response.text;
  if (!text) throw new Error("Failed to generate plan");
  return JSON.parse(text) as SophiePlan;
};

export const generateSophieAudio = async (text: string): Promise<string> => {
  const ai = await getAiClient();

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' }, 
        },
      },
    },
  });

  const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!audioData) throw new Error("Failed to generate audio");
  return audioData;
};

export const generateSophieVideo = async (
  characterDataUrl: string,
  prompt: string,
  resolution: VideoResolution = '720p'
): Promise<string> => {
  const ai = await getAiClient();

  // 1. Parse Data URL to ensure correct MIME type
  const { mimeType, data } = parseDataUrl(characterDataUrl);

  // Using fast-generate-preview for speed. 
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt, 
    image: {
      imageBytes: data,
      mimeType: mimeType, 
    },
    config: {
      numberOfVideos: 1,
      resolution: resolution, // Dynamic resolution
      aspectRatio: '9:16'
    }
  });

  // Polling loop
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  // 2. Check for errors
  if (operation.error) {
    const errorMsg = operation.error.message || "Unknown error";
    console.error("Veo API Error:", operation.error);
    throw new Error(`Video generation failed: ${errorMsg}`);
  }

  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!videoUri) throw new Error("Video generation completed successfully but returned no video URI.");

  // 3. Download the video content to create a local Blob URL
  // This ensures the video can be played and downloaded without CORS/Auth issues in the UI
  try {
      const apiKey = process.env.API_KEY; 
      // Ensure we use the correct separator if the URI already has params
      const separator = videoUri.includes('?') ? '&' : '?';
      const fetchUrl = apiKey ? `${videoUri}${separator}key=${apiKey}` : videoUri;

      console.log("Downloading video...");
      const response = await fetch(fetchUrl);
      if (!response.ok) {
          throw new Error(`Failed to download video file: ${response.statusText}`);
      }
      const blob = await response.blob();
      return URL.createObjectURL(blob); 
  } catch (error) {
      console.warn("Failed to fetch video blob, falling back to direct URI.", error);
      // Fallback: return the URI with key appended
      const apiKey = process.env.API_KEY;
      const separator = videoUri.includes('?') ? '&' : '?';
      return apiKey ? `${videoUri}${separator}key=${apiKey}` : videoUri;
  }
};

export const ensureApiKeySelected = async (): Promise<boolean> => {
    const win = window as any;
    if (win.aistudio) {
        if (await win.aistudio.hasSelectedApiKey()) {
            return true;
        }
        try {
            const success = await win.aistudio.openSelectKey();
            return success;
        } catch (e) {
            console.error(e);
            return false;
        }
    }
    // Fallback for dev environments
    return !!process.env.API_KEY; 
};

import React, { useState, useEffect } from 'react';
import { Button } from './components/Button';
import { GlassCard } from './components/GlassCard';
import { FileUpload } from './components/FileUpload';
import { generateSophiePlan, generateSophieAudio, generateSophieVideo, ensureApiKeySelected } from './services/geminiService';
import { SophiePlan, AppStep, HistoryItem, Language, VideoResolution, AmbientSound } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('intro');
  const [characterImg, setCharacterImg] = useState<string | null>(null);
  const [clothesImg, setClothesImg] = useState<string | null>(null);

  // Configuration State
  const [location, setLocation] = useState('Luxury Riyadh Villa at Sunset');
  const [dialogue, setDialogue] = useState('Welcome to my world.');
  const [language, setLanguage] = useState<Language>('saudi');

  // New Configuration State
  const [resolution, setResolution] = useState<VideoResolution>('720p');
  const [ambient, setAmbient] = useState<AmbientSound>('none');

  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<SophiePlan | null>(null);
  const [media, setMedia] = useState<{ videoUri?: string; audioBase64?: string }>({});
  const [error, setError] = useState<string | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // Load history on mount
  useEffect(() => {
    const saved = localStorage.getItem('sophie_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history helper
  const saveToHistory = (newPlan: SophiePlan, newMedia: { videoUri?: string; audioBase64?: string }) => {
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      plan: newPlan,
      media: newMedia,
      language: language,
      resolution: resolution,
      ambient: ambient
    };

    // Prepend new item, limit to last 10 to save space
    const updated = [newItem, ...history].slice(0, 10);
    setHistory(updated);
    localStorage.setItem('sophie_history', JSON.stringify(updated));
  };

  const loadFromHistory = (item: HistoryItem) => {
    setPlan(item.plan);
    setMedia(item.media);
    setLanguage(item.language);
    setResolution(item.resolution || '720p');
    setAmbient(item.ambient || 'none');
    setStep('result');
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('sophie_history');
  };

  // --- Handlers ---

  const handleGeneratePlan = async () => {
    if (!characterImg) {
      setError("Please upload a character image.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // 1. Generate The Plan (Text/JSON)
      // Pass the full Data URL so the service can extract MIME types correctly
      const planResult = await generateSophiePlan(
        characterImg,
        clothesImg ? [clothesImg] : [],
        location,
        dialogue,
        language
      );
      setPlan(planResult);
      setStep('planning');
    } catch (err: any) {
      setError(err.message || "Failed to generate plan.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateMedia = async () => {
    if (!plan || !characterImg) return;

    setIsLoading(true);
    setError(null);
    setStep('generating');

    try {
      // 2. Ensure Key for Veo
      const hasKey = await ensureApiKeySelected();
      if (!hasKey) {
        throw new Error("API Key selection is required for video generation.");
      }

      // 3. Generate Video & Audio in parallel
      // Pass the selected resolution to generateSophieVideo
      const [videoUri, audioData] = await Promise.all([
        generateSophieVideo(characterImg, plan.veoPrompt, resolution),
        generateSophieAudio(plan.dialogue)
      ]);

      const newMedia = { videoUri, audioBase64: audioData };
      setMedia(newMedia);

      // Save to history automatically
      saveToHistory(plan, newMedia);

      setStep('result');

    } catch (err: any) {
      console.error(err);
      setError("Generation failed. " + (err.message || ""));
      setStep('planning'); // Go back
    } finally {
      setIsLoading(false);
    }
  };

  // --- Renders ---

  const renderIntro = () => (
    <div className="flex flex-col items-center text-center space-y-8 animate-fade-in max-w-2xl mx-auto">
