import React, { useState, useEffect } from 'react';
import { Button } from './components/Button';
import { GlassCard } from './components/GlassCard';
import { FileUpload } from './components/FileUpload';
import { generateSophiePlan, generateSophieAudio, generateSophieVideo, ensureApiKeySelected } from './services/geminiService';
import { SophiePlan, AppStep, HistoryItem, Language, VideoResolution, AmbientSound } from './types';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('intro');
  const [characterImg, setCharacterImg] = useState<string | null>(null);
  const [clothesImg, setClothesImg] = useState<string | null>(null);

  // Configuration State
  const [location, setLocation] = useState('Luxury Riyadh Villa at Sunset');
  const [dialogue, setDialogue] = useState('Welcome to my world.');
  const [language, setLanguage] = useState<Language>('saudi');

  // New Configuration State
  const [resolution, setResolution] = useState<VideoResolution>('720p');
  const [ambient, setAmbient] = useState<AmbientSound>('none');

  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<SophiePlan | null>(null);
  const [media, setMedia] = useState<{ videoUri?: string; audioBase64?: string }>({});
  const [error, setError] = useState<string | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // Load history on mount
  useEffect(() => {
    const saved = localStorage.getItem('sophie_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history helper
  const saveToHistory = (newPlan: SophiePlan, newMedia: { videoUri?: string; audioBase64?: string }) => {
    const newItem: HistoryItem = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      plan: newPlan,
      media: newMedia,
      language: language,
      resolution: resolution,
      ambient: ambient
    };

    // Prepend new item, limit to last 10 to save space
    const updated = [newItem, ...history].slice(0, 10);
    setHistory(updated);
    localStorage.setItem('sophie_history', JSON.stringify(updated));
  };

  const loadFromHistory = (item: HistoryItem) => {
    setPlan(item.plan);
    setMedia(item.media);
    setLanguage(item.language);
    setResolution(item.resolution || '720p');
    setAmbient(item.ambient || 'none');
    setStep('result');
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('sophie_history');
  };

  // --- Handlers ---

  const handleGeneratePlan = async () => {
    if (!characterImg) {
      setError("Please upload a character image.");
      return;
    }

    setIsLoading(true);
    setError(null);
    try {
      // 1. Generate The Plan (Text/JSON)
      // Pass the full Data URL so the service can extract MIME types correctly
      const planResult = await generateSophiePlan(
        characterImg,
        clothesImg ? [clothesImg] : [],
        location,
        dialogue,
        language
      );
      setPlan(planResult);
      setStep('planning');
    } catch (err: any) {
      setError(err.message || "Failed to generate plan.");
    } finally {
      setIsLoading(false);
    }
  };

  const handlePlanEdit = (field: keyof SophiePlan, value: string) => {
    if (!plan) return;
    setPlan({
      ...plan,
      [field]: value
    });
  };

  const handleGenerateMedia = async () => {
    if (!plan || !characterImg) return;

    setIsLoading(true);
    setError(null);
    setStep('generating');

    try {
      // 2. Ensure Key for Veo
      const hasKey = await ensureApiKeySelected();
      if (!hasKey) {
        throw new Error("API Key selection is required for video generation.");
      }

      // 3. Generate Video & Audio in parallel
      // Pass the selected resolution to generateSophieVideo
      const [videoUri, audioData] = await Promise.all([
        generateSophieVideo(characterImg, plan.veoPrompt, resolution),
        generateSophieAudio(plan.dialogue)
      ]);

      const newMedia = { videoUri, audioBase64: audioData };
      setMedia(newMedia);

      // Save to history automatically
      saveToHistory(plan, newMedia);

      setStep('result');

    } catch (err: any) {
      console.error(err);
      setError("Generation failed. " + (err.message || ""));
      setStep('planning'); // Go back
    } finally {
      setIsLoading(false);
    }
  };

  // --- Renders ---

  const renderIntro = () => (
    <div className="flex flex-col items-center text-center space-y-8 animate-fade-in max-w-2xl mx-auto">
      <h1 className="text-6xl md:text-8xl luxury-gradient font-cinzel tracking-widest mb-4">SOPHIE</h1>
      <p className="text-xl text-neutral-400 font-light tracking-wide max-w-lg">
        THE PREMIER AI AVATAR PLATFORM FOR THE GCC. <br />
        <span className="text-amber-500">ELEGANCE. INTELLIGENCE. LUXURY.</span>
      </p>
      <div className="flex flex-col md:flex-row gap-4 mt-8">
        <Button onClick={() => setStep('upload')} className="text-lg px-12 py-4">
          Begin Experience
        </Button>
        <Button variant="outline" onClick={() => setStep('history')} className="text-lg px-12 py-4">
          View History
        </Button>
      </div>
    </div>
  );

  const renderHistory = () => (
    <div className="w-full max-w-6xl mx-auto space-y-8">
      <div className="flex items-center justify-between border-b border-neutral-800 pb-4">
        <h2 className="text-3xl text-amber-500 font-cinzel">Archive</h2>
        <div className="flex gap-4">
           <Button variant="outline" onClick={clearHistory} disabled={history.length === 0} className="text-xs">
             Clear Archive
           </Button>
           <button onClick={() => setStep('intro')} className="text-neutral-500 hover:text-white transition-colors uppercase text-sm">
             Back to Home
           </button>
        </div>
      </div>

      {history.length === 0 ? (
        <div className="text-center py-20 bg-neutral-900/30 rounded-lg border border-neutral-800 border-dashed">
          <p className="text-neutral-500">No generated avatars found in history.</p>
          <Button onClick={() => setStep('upload')} variant="outline" className="mt-4">
            Create First Avatar
          </Button>
        </div>
      ) : (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {history.map((item) => (
            <GlassCard key={item.id} className="group hover:border-amber-500/50 transition-all duration-300">
               <div className="flex justify-between items-start mb-2">
                 <span className="text-xs text-amber-500 uppercase font-bold tracking-widest">
                   {new Date(item.timestamp).toLocaleDateString()}
                 </span>
                 <div className="flex gap-2">
                    <span className="text-[10px] bg-neutral-800 text-neutral-400 px-2 py-1 rounded uppercase">
                        {item.resolution || '720p'}
                    </span>
                    <span className="text-[10px] bg-neutral-800 text-neutral-400 px-2 py-1 rounded uppercase">
                        {item.language}
                    </span>
                 </div>
               </div>

               <p className="text-white font-cinzel text-lg line-clamp-2 mb-2">"{item.plan.dialogue}"</p>
               <p className="text-neutral-500 text-xs mb-4 line-clamp-2">{item.plan.wardrobeStyling}</p>

               <Button fullWidth onClick={() => loadFromHistory(item)} className="text-xs py-2">
                 Replay Video
               </Button>
            </GlassCard>
          ))}
        </div>
      )}
    </div>
  );

  const renderUpload = () => (
    <div className="w-full max-w-4xl mx-auto grid md:grid-cols-2 gap-8">
      <GlassCard className="space-y-6">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">The Muse</h2>
        <FileUpload 
          label="Character Base" 
          onFileSelect={setCharacterImg} 
          preview={characterImg}
        />
      </GlassCard>

      <GlassCard className="space-y-6">
        <h2 className="text-2xl text-amber-500 font-cinzel border-b border-neutral-800 pb-2">The Wardrobe</h2>
        <FileUpload 
          label="Outfit / Abaya" 
          onFileSelect={setClothesImg} 
          preview={clothesImg}
        />
        <p className="text-xs text-neutral-500 mt-2">*Upload an image of the desired clothing style.</p>

        <div className="pt-8 flex justify-end">
           <Button 
            disabled={!characterImg}
            onClick={() => setStep('configure')}
           >
             Next: Styling
           </Button>
        </div>
      </GlassCard>
    </div>
  );

  const renderConfigure = () => (
    <GlassCard className="max-w-3xl mx-auto w-full space-y-8">
      <div className="flex items-center justify-between border-b border-neutral-800 pb-4">
        <h2 className="text-3xl text-amber-500 font-cinzel">Direct The Scene</h2>
        <span className="text-neutral-500 text-sm tracking-widest">STEP 02/03</span>
      </div>

      <div className="space-y-6">
        {/* Language Selection */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-amber-500 text-sm font-bold mb-3 uppercase">Primary Language</label>
            <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => setLanguage('saudi')}
                  className={`p-3 border text-center transition-all duration-300 uppercase tracking-widest text-xs font-bold ${
                    language === 'saudi' 
                    ? 'bg-amber-600/20 border-amber-500 text-amber-400' 
                    : 'bg-neutral-900 border-neutral-700 text-neutral-500 hover:border-neutral-500'
                  }`}
                >
                  Saudi
                </button>
                <button 
                  onClick={() => setLanguage('english')}
                  className={`p-3 border text-center transition-all duration-300 uppercase tracking-widest text-xs font-bold ${
                    language === 'english' 
                    ? 'bg-amber-600/20 border-amber-500 text-amber-400' 
                    : 'bg-neutral-900 border-neutral-700 text-neutral-500 hover:border-neutral-500'
                  }`}
                >
                  English
                </button>
            </div>
          </div>

          <div>
             <label className="block text-amber-500 text-sm font-bold mb-3 uppercase">Video Quality</label>
             <div className="grid grid-cols-2 gap-2">
                <button 
                  onClick={() => setResolution('720p')}
                  className={`p-3 border text-center transition-all duration-300 uppercase tracking-widest text-xs font-bold ${
                    resolution === '720p' 
                    ? 'bg-amber-600/20 border-amber-500 text-amber-400' 
                    : 'bg-neutral-900 border-neutral-700 text-neutral-500 hover:border-neutral-500'
                  }`}
                >
                  720p (Std)
                </button>
                <button 
                  onClick={() => setResolution('1080p')}
                  className={`p-3 border text-center transition-all duration-300 uppercase tracking-widest text-xs font-bold ${
                    resolution === '1080p' 
                    ? 'bg-amber-600/20 border-amber-500 text-amber-400 shadow-[0_0_10px_rgba(217,119,6,0.3)]' 
                    : 'bg-neutral-900 border-neutral-700 text-neutral-500 hover:border-neutral-500'
                  }`}
                >
                  1080p (HD)
                </button>
             </div>
          </div>
        </div>

        <div>
          <label className="block text-amber-500 text-sm font-bold mb-3 uppercase">Ambient Sound (Background)</label>
          <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
             {(['none', 'luxury_lounge', 'desert_wind', 'urban_city', 'ocean_waves'] as AmbientSound[]).map((snd) => (
                <button
                  key={snd}
                  onClick={() => setAmbient(snd)}
                  className={`p-2 border text-center transition-all duration-300 uppercase tracking-widest text-[10px] font-bold ${
                    ambient === snd
                    ? 'bg-amber-600/20 border-amber-500 text-amber-400'
                    : 'bg-neutral-900 border-neutral-700 text-neutral-500 hover:border-neutral-500'
                  }`}
                >
                  {snd.replace('_', ' ')}
                </button>
             ))}
          </div>
        </div>

        <div>
          <label className="block text-amber-500 text-sm font-bold mb-2 uppercase">Location & Atmosphere</label>
          <input 
            type="text" 
            value={location}
            onChange={(e) => setLocation(e.target.value)}
            className="w-full bg-neutral-950 border border-neutral-700 p-4 text-white focus:border-amber-500 focus:outline-none transition-colors"
            placeholder="e.g. Luxury Riyadh villa at sunset..."
          />
        </div>

        <div>
          <label className="block text-amber-500 text-sm font-bold mb-2 uppercase">Dialogue Request</label>
          <textarea 
            rows={3}
            value={dialogue}
            onChange={(e) => setDialogue(e.target.value)}
            className="w-full bg-neutral-950 border border-neutral-700 p-4 text-white focus:border-amber-500 focus:outline-none transition-colors"
            placeholder="What should Sophie say?"
          />
        </div>
      </div>

      <div className="flex justify-between items-center pt-4">
        <button onClick={() => setStep('upload')} className="text-neutral-500 hover:text-white transition-colors uppercase text-sm">Back</button>
        <Button onClick={handleGeneratePlan} disabled={isLoading}>
          {isLoading ? 'Analyzing...' : 'Generate Creative Plan'}
        </Button>
      </div>
    </GlassCard>
  );

  const renderPlanning = () => (
    <div className="max-w-5xl mx-auto w-full grid lg:grid-cols-2 gap-8">
      {/* Left: The Plan Details */}
      <GlassCard className="space-y-6 h-full flex flex-col">
        <div className="flex justify-between items-center border-b border-neutral-800 pb-2">
            <h2 className="text-2xl text-amber-500 font-cinzel">Edit Direction</h2>
            <div className="flex gap-2">
                <span className="text-xs bg-neutral-800 text-neutral-400 px-2 py-1 rounded uppercase tracking-wider">{language}</span>
                <span className="text-xs bg-neutral-800 text-amber-500 px-2 py-1 rounded uppercase tracking-wider font-bold">{resolution}</span>
            </div>
        </div>

        {plan && (
          <div className="space-y-4 text-sm flex-1 overflow-y-auto pr-2 custom-scrollbar">
            <div>
              <label className="text-neutral-500 uppercase text-xs mb-1 block font-bold">Target Dialogue</label>
              <textarea
                value={plan.dialogue}
                onChange={(e) => handlePlanEdit('dialogue', e.target.value)}
                dir={language === 'saudi' ? 'rtl' : 'ltr'}
                rows={3}
                className={`w-full bg-neutral-950/50 border border-neutral-800 p-3 text-white focus:border-amber-500 focus:outline-none transition-colors rounded ${language === 'saudi' ? 'arabic-text' : 'font-serif'}`}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-neutral-500 uppercase text-xs mb-1 block font-bold">Emotional Tone</label>
                <input
                  type="text"
                  value={plan.emotionalTone}
                  onChange={(e) => handlePlanEdit('emotionalTone', e.target.value)}
                  className="w-full bg-neutral-950/50 border border-neutral-800 p-2 text-amber-100 focus:border-amber-500 focus:outline-none rounded text-xs"
                />
              </div>
              <div>
                <label className="text-neutral-500 uppercase text-xs mb-1 block font-bold">Lighting</label>
                <input
                  type="text"
                  value={plan.sceneLighting}
                  onChange={(e) => handlePlanEdit('sceneLighting', e.target.value)}
                  className="w-full bg-neutral-950/50 border border-neutral-800 p-2 text-amber-100 focus:border-amber-500 focus:outline-none rounded text-xs"
                />
              </div>
            </div>

            <div>
              <label className="text-neutral-500 uppercase text-xs mb-1 block font-bold">Wardrobe Styling</label>
              <textarea
                rows={2}
                value={plan.wardrobeStyling}
                onChange={(e) => handlePlanEdit('wardrobeStyling', e.target.value)}
                className="w-full bg-neutral-950/50 border border-neutral-800 p-3 text-neutral-300 italic focus:border-amber-500 focus:outline-none rounded"
              />
            </div>

            <div>
              <label className="text-neutral-500 uppercase text-xs mb-1 block font-bold">Video Generation Prompt (Veo)</label>
              <p className="text-[10px] text-neutral-500 mb-1">Edit this to change exactly what the video model sees.</p>
              <textarea
                rows={4}
                value={plan.veoPrompt}
                onChange={(e) => handlePlanEdit('veoPrompt', e.target.value)}
                className="w-full bg-neutral-900 border border-neutral-700 p-3 text-neutral-400 text-xs focus:border-amber-500 focus:text-white focus:outline-none rounded font-mono"
              />
            </div>
          </div>
        )}
      </GlassCard>

      {/* Right: Confirmation */}
      <div className="flex flex-col space-y-8">
        <GlassCard className="flex-1 flex flex-col justify-center items-center text-center space-y-4 border-amber-500/20">
          <h3 className="text-xl font-cinzel text-white">Ready to Produce?</h3>
          <p className="text-neutral-400 text-sm max-w-xs">
            This will generate a high-definition ({resolution}) video using Veo and synthesize the voice based on the <strong className="text-amber-500">edited plan</strong> on the left.
            {ambient !== 'none' && <span className="block mt-1 text-amber-500/70 text-xs">+ {ambient.replace('_', ' ')} Ambience</span>}
            <br/><br/>
            <span className="text-amber-600 text-xs">REQUIRES PAID API KEY SELECTION</span>
          </p>
          <Button onClick={handleGenerateMedia} className="w-full max-w-xs py-4 shadow-[0_0_30px_rgba(217,119,6,0.15)]">
            Generate Cinematic Media
          </Button>
          <button onClick={() => setStep('configure')} className="text-xs text-neutral-600 hover:text-neutral-400 mt-4 uppercase">Reset Parameters</button>
        </GlassCard>
      </div>
    </div>
  );

  const renderGenerating = () => (
    <div className="flex flex-col items-center justify-center min-h-[50vh] space-y-8 text-center">
      <div className="relative w-24 h-24">
        <div className="absolute inset-0 border-4 border-neutral-800 rounded-full"></div>
        <div className="absolute inset-0 border-t-4 border-amber-500 rounded-full animate-spin"></div>
      </div>
      <div>
        <h2 className="text-3xl font-cinzel text-white mb-2">Producing Content</h2>
        <p className="text-amber-500/80 animate-pulse">Rendering {resolution} video & synthesizing audio...</p>
        <p className="text-neutral-600 text-sm mt-4">This may take up to 2 minutes.</p>
      </div>
    </div>
  );

  const renderResult = () => (
    <div className="max-w-6xl mx-auto w-full grid lg:grid-cols-3 gap-8">
      {/* Video Result */}
      <GlassCard className="lg:col-span-2 p-0 overflow-hidden relative bg-black aspect-[9/16] lg:aspect-video flex flex-col items-center justify-center">
        {media.videoUri ? (
          <>
            <video 
              src={media.videoUri} 
              controls 
              autoPlay 
              loop 
              className="w-full h-full object-contain bg-black"
              // Removed crossOrigin="anonymous" to avoid CORS errors on playback if headers missing
            />
            {/* Download Action Bar */}
            <div className="absolute top-4 right-4 z-10">
               <a 
                 href={media.videoUri}
                 download={`sophie-avatar-${resolution}.mp4`}
                 target="_blank"
                 rel="noopener noreferrer"
                 className="flex items-center gap-2 bg-neutral-900/80 hover:bg-amber-600 text-white px-4 py-2 rounded-full backdrop-blur-md transition-all border border-neutral-700 hover:border-amber-500 shadow-lg text-xs font-bold uppercase tracking-wider"
               >
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                 Download {resolution}
               </a>
            </div>
            {/* Ambient Sound Indicator */}
            {ambient !== 'none' && (
                <div className="absolute bottom-4 left-4 z-10 bg-neutral-900/60 backdrop-blur px-3 py-1 rounded-full flex items-center gap-2 border border-neutral-700">
                    <div className="w-2 h-2 bg-amber-500 rounded-full animate-pulse"></div>
                    <span className="text-[10px] uppercase text-neutral-300 tracking-wider">Ambience: {ambient.replace('_', ' ')}</span>
                </div>
            )}
          </>
        ) : (
          <p className="text-red-500">Video generation unavailable.</p>
        )}
      </GlassCard>

      {/* Audio & Details */}
      <div className="flex flex-col space-y-6">
         <GlassCard>
          <div className="flex justify-between items-center mb-4">
             <h3 className="text-amber-500 font-cinzel">Voice Synthesis</h3>
             {media.audioBase64 && (
                <a 
                  href={`data:audio/mp3;base64,${media.audioBase64}`} 
                  download="sophie-voice.mp3"
                  className="text-xs text-neutral-500 hover:text-white transition-colors"
                >
                  DOWNLOAD MP3
                </a>
             )}
          </div>
          {media.audioBase64 ? (
            <audio controls className="w-full" src={`data:audio/mp3;base64,${media.audioBase64}`} />
          ) : (
            <p className="text-neutral-500 text-sm">Audio unavailable</p>
          )}
         </GlassCard>

         <GlassCard className="flex-1">
           <h3 className="text-amber-500 font-cinzel mb-4">Production Notes</h3>
           <div className="space-y-4 text-sm text-neutral-300">
             <div className="flex gap-2 mb-2">
                 <span className="text-[10px] bg-amber-900/40 text-amber-500 border border-amber-900 px-2 py-0.5 rounded uppercase tracking-wider">{resolution}</span>
                 {ambient !== 'none' && <span className="text-[10px] bg-neutral-800 text-neutral-400 px-2 py-0.5 rounded uppercase tracking-wider">{ambient.replace('_', ' ')}</span>}
             </div>
             <p><span className="text-neutral-500 block text-xs uppercase">Dialogue ({language})</span> {plan?.dialogue}</p>
             <p><span className="text-neutral-500 block text-xs uppercase">Styling</span> {plan?.wardrobeStyling}</p>
           </div>

           <div className="mt-8 pt-8 border-t border-neutral-800 flex flex-col gap-3">
             <Button variant="outline" fullWidth onClick={() => setStep('intro')}>Create New Avatar</Button>
             <Button variant="secondary" fullWidth onClick={() => setStep('history')} className="text-xs">View Archive</Button>
           </div>
         </GlassCard>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-black text-neutral-200 selection:bg-amber-500/30 selection:text-amber-200 flex flex-col">
      {/* Header */}
      <header className="py-6 px-8 border-b border-neutral-900 flex justify-between items-center sticky top-0 bg-black/80 backdrop-blur-lg z-50">
        <div className="text-2xl font-cinzel font-bold text-white tracking-widest cursor-pointer" onClick={() => setStep('intro')}>
          SOPHIE <span className="text-amber-600">.</span>
        </div>

        <div className="flex items-center gap-4">
            <button 
                onClick={() => setStep('history')} 
                className="hidden md:block text-xs font-bold text-neutral-500 hover:text-amber-500 tracking-[0.2em] transition-colors uppercase"
            >
                Archive
            </button>
            <div className="w-px h-4 bg-neutral-800 hidden md:block"></div>
            <div className="text-xs font-bold text-neutral-500 tracking-[0.2em] hidden md:block">
            AI AVATAR LUXURY SUITE
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col p-4 md:p-8 lg:p-12 relative overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-amber-600/10 rounded-full blur-[128px] pointer-events-none"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-amber-900/10 rounded-full blur-[128px] pointer-events-none"></div>

        <div className="relative z-10 w-full max-w-7xl mx-auto flex-1 flex flex-col justify-center">
          {error && (
            <div className="mb-6 p-4 border border-red-900/50 bg-red-900/10 text-red-200 text-center rounded">
              {error}
            </div>
          )}

          {step === 'intro' && renderIntro()}
          {step === 'upload' && renderUpload()}
          {step === 'history' && renderHistory()}
          {step === 'configure' && renderConfigure()}
          {step === 'planning' && renderPlanning()}
          {step === 'generating' && renderGenerating()}
          {step === 'result' && renderResult()}
        </div>
      </main>

      {/* Footer */}
      <footer className="py-6 text-center text-neutral-700 text-xs tracking-widest uppercase">
        Powered by Marwan & Khayyam • Sophie Avatar Platform © 2025
      </footer>
    </div>
  );
};

export default App;
